#!/usr/bin/env node
// AUTO-GENERATED by @sentinel/engine-copilot — do not edit manually.
// This file is a static runtime wrapper — it does NOT embed checks config.
// Edit checks.yaml and run `npx sentinel update` to regenerate checks.immutable.json.

import { execSync } from "node:child_process";
import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";

// ─── Helpers ─────────────────────────────────────────────────────────────────

function loadConfig() {
  const configPath = join(process.cwd(), ".github/sentinel/generated/checks.immutable.json");
  if (!existsSync(configPath)) {
    return null;
  }
  return JSON.parse(readFileSync(configPath, "utf8"));
}

function getStagedFiles() {
  try {
    const out = execSync("git diff --cached --name-only", {
      encoding: "utf8",
      stdio: ["pipe", "pipe", "ignore"],
    });
    return out.trim().split("\n").filter(Boolean);
  } catch {
    return [];
  }
}

function matchesWhen(when, changedFiles) {
  if (!when) return true;
  // No staged files — run all checks
  if (changedFiles.includes("__all__") || changedFiles.length === 0) return true;
  const patterns = {
    frontend: [
      /\.(tsx|jsx|css|scss)$/,
      /tailwind\.config\./,
      /postcss\.config\./,
      /^apps\/(builder|web)\//,
    ],
    backend: [
      /\/(api|server|routes|controllers|middleware)\//,
      /^packages\/[^/]+\/src\//,
    ],
    prisma: [/\.prisma$/, /\/prisma\//],
    socket: [/\/(socket|ws|websocket)\//],
    visual: [/\.stories\.(tsx?|jsx?)$/, /__screenshots__\//, /\.snap$/],
  };
  if (when in patterns) {
    const regexes = patterns[when] ?? [];
    return changedFiles.some((f) => regexes.some((re) => re.test(f)));
  }
  // Custom regex
  const re = new RegExp(when);
  return changedFiles.some((f) => re.test(f));
}

function runCheck(check) {
  if (!check.cmd) return { status: "pending" };
  try {
    const output = execSync(check.cmd, { encoding: "utf8", timeout: 60000, stdio: "pipe" });
    return { status: "pass", output };
  } catch (e) {
    const output = [e.stdout, e.stderr].filter(Boolean).join("\n");
    return { status: "fail", output, exitCode: e.status ?? 1 };
  }
}

// ─── Extension entry-point ────────────────────────────────────────────────────

export default {
  // Invoked before the agent marks a task complete
  async beforeTaskComplete() {
    const changedFiles = getStagedFiles();

    // ── Step 1: if checks.yaml is staged, re-sync BEFORE loading config ────────
    // This ensures checks.immutable.json is always fresh and the rest of the
    // evaluation chain runs against the correct checks — not a stale snapshot.
    if (changedFiles.some((f) => /^checks\.yaml$/.test(f))) {
      const sync = runCheck({ label: "Sentinel sync — checks.yaml changed", cmd: "npx sentinel update" });
      if (sync.status === "fail") {
        return {
          decision: "block",
          reason: `Sentinel: checks.yaml has changed but \`sentinel update\` failed:\n\n${(sync.output ?? "").trim()}\n\nFix the error above, then retry.`,
        };
      }
    }

    // ── Step 2: load config (freshly written if step 1 ran) ───────────────────
    const config = loadConfig();
    if (!config) {
      return {
        decision: "block",
        reason: "Sentinel: .github/sentinel/generated/checks.immutable.json not found — run: npx sentinel update",
      };
    }

    const failures = [];

    for (const check of config.deterministic) {
      if (!matchesWhen(check.when, changedFiles)) continue;
      const result = runCheck(check);
      if (result.status === "fail") {
        failures.push({ check, result });
      }
    }

    if (failures.length > 0) {
      const summary = failures
        .map((f) => `  ✗ [${f.check.label}]\n${(f.result.output ?? "").trim()}`)
        .join("\n\n");
      return {
        decision: "block",
        reason: `Sentinel eval-guard: ${failures.length} check(s) failed:\n\n${summary}\n\nFix the above issues before marking the task complete.`,
      };
    }

    // Surface prompt checks as a reminder
    const promptChecks = config.prompt.filter((c) =>
      matchesWhen(c.when, changedFiles),
    );
    if (promptChecks.length > 0) {
      const list = promptChecks.map((c) => `  □ [${c.label}] ${c.prompt ?? ""}`).join("\n");
      console.log(`[sentinel] Agent prompts to act on:\n${list}\n`);
    }

    return { decision: "allow" };
  },
};
